#include<bits/stdc++.h>
using namespace std;
const long long N=5e5+5,XjL=520;
long long f[101][N],a[101],b[101],n; 
int main(){
	memset(f,~0x3f3f3f,sizeof f);
	cin>>n;
	f[0][500*100]=0;
	for (long long i=1;i<=n;i++) {
		cin>>a[i]>>b[i];
		for (long long j=100000+a[i]-b[i];j>=a[i]-b[i];j--) {
			f[i][j]=max(f[i-1][j],f[i-1][j-(a[i]-b[i])]+a[i]+b[i]);
		}
	}
	cout<<f[n][50000];
	return 0;
}
